import{_ as r,c as a,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"隱私條款：了解資料保護 | OpenCodeDocs","description":"了解 OpenCodeDocs 的隱私政策和資料保護措施。我們如何收集、使用、儲存您的個人資訊，以及您享有的資料權利。","frontmatter":{"title":"隱私條款：了解資料保護 | OpenCodeDocs","sidebarTitle":"你的資料去哪了","subtitle":"隱私條款：了解資料保護","description":"了解 OpenCodeDocs 的隱私政策和資料保護措施。我們如何收集、使用、儲存您的個人資訊，以及您享有的資料權利。","order":10},"headers":[],"relativePath":"zh-tw/privacy.md","filePath":"zh-tw/privacy.md"}'),i={name:"zh-tw/privacy.md"};function e(n,o,s,g,h,c){return l(),a("div",null,[...o[0]||(o[0]=[t('<h1 id="隱私條款" tabindex="-1">隱私條款 <a class="header-anchor" href="#隱私條款" aria-label="Permalink to &quot;隱私條款&quot;">​</a></h1><p>最後更新日期：2026-01-01</p><p>感謝您使用 OpenCodeDocs。我們非常重視您的隱私和個人資訊保護。本隱私條款將幫助您了解我們如何收集、使用、儲存和保護您的個人資訊。</p><h2 id="_1-我們收集的資訊" tabindex="-1">1. 我們收集的資訊 <a class="header-anchor" href="#_1-我們收集的資訊" aria-label="Permalink to &quot;1. 我們收集的資訊&quot;">​</a></h2><p>在您使用 OpenCodeDocs 服務時，我們可能會收集以下類型的資訊：</p><h3 id="帳號資訊" tabindex="-1">帳號資訊 <a class="header-anchor" href="#帳號資訊" aria-label="Permalink to &quot;帳號資訊&quot;">​</a></h3><ul><li><strong>電子郵件</strong>：用於帳號註冊、登入驗證和重要通知</li><li><strong>使用者名稱</strong>：您選擇的顯示名稱</li><li><strong>GitHub 帳號資訊</strong>：如您選擇使用 GitHub 登入，我們會取得您的公開資訊</li></ul><h3 id="使用資料" tabindex="-1">使用資料 <a class="header-anchor" href="#使用資料" aria-label="Permalink to &quot;使用資料&quot;">​</a></h3><ul><li><strong>瀏覽記錄</strong>：您造訪的教學頁面和時間</li><li><strong>互動行為</strong>：程式碼複製、章節跳轉等操作</li><li><strong>搜尋記錄</strong>：您在站內的搜尋關鍵字</li></ul><h3 id="裝置資訊" tabindex="-1">裝置資訊 <a class="header-anchor" href="#裝置資訊" aria-label="Permalink to &quot;裝置資訊&quot;">​</a></h3><ul><li><strong>瀏覽器類型</strong>：Chrome、Firefox、Safari 等</li><li><strong>作業系統</strong>：Windows、macOS、Linux 等</li><li><strong>IP 位址</strong>：用於安全防護和地區優化</li></ul><h2 id="_2-資訊使用方式" tabindex="-1">2. 資訊使用方式 <a class="header-anchor" href="#_2-資訊使用方式" aria-label="Permalink to &quot;2. 資訊使用方式&quot;">​</a></h2><p>我們收集的資訊將用於以下目的：</p><ul><li><strong>提供服務</strong>：確保您能夠正常造訪和使用教學內容</li><li><strong>個人化體驗</strong>：記住您的閱讀進度和偏好設定</li><li><strong>產品改進</strong>：分析使用模式，優化內容和功能</li><li><strong>安全保障</strong>：偵測異常行為，防止濫用</li><li><strong>通知發送</strong>：發送教學更新提醒和重要公告（可選擇退訂）</li></ul><h2 id="_3-資訊共享與揭露" tabindex="-1">3. 資訊共享與揭露 <a class="header-anchor" href="#_3-資訊共享與揭露" aria-label="Permalink to &quot;3. 資訊共享與揭露&quot;">​</a></h2><p>我們不會出售您的個人資訊。僅在以下情況下可能共享：</p><ul><li><strong>第三方服務提供商</strong>：如 Vercel（託管）、Plausible（分析），他們僅能存取履行職責所需的資訊</li><li><strong>法律要求</strong>：依據法律法規或政府要求進行揭露</li><li><strong>權益保護</strong>：為保護 OpenCodeDocs 及使用者權益的必要情況</li></ul><h2 id="_4-資料儲存與安全" tabindex="-1">4. 資料儲存與安全 <a class="header-anchor" href="#_4-資料儲存與安全" aria-label="Permalink to &quot;4. 資料儲存與安全&quot;">​</a></h2><ul><li><strong>儲存位置</strong>：資料儲存於位於美國和亞太地區的安全伺服器</li><li><strong>加密措施</strong>：傳輸資料使用 TLS/SSL 加密，敏感資料使用 AES-256 加密儲存</li><li><strong>存取控制</strong>：嚴格限制內部人員對資料的存取權限</li><li><strong>保留期限</strong>：帳號註銷後，個人資料將在 30 天內刪除</li></ul><h2 id="_5-您的權利" tabindex="-1">5. 您的權利 <a class="header-anchor" href="#_5-您的權利" aria-label="Permalink to &quot;5. 您的權利&quot;">​</a></h2><p>根據《個人資訊保護法》及 GDPR，您享有以下權利：</p><ul><li><strong>存取權</strong>：您有權查看我們持有的關於您的個人資訊</li><li><strong>更正權</strong>：您有權要求更正不準確的個人資訊</li><li><strong>刪除權</strong>：您有權要求刪除您的個人資訊</li><li><strong>匯出權</strong>：您有權以通用格式匯出您的資料</li><li><strong>撤回同意</strong>：您有權隨時撤回之前給予的同意</li></ul><p>如需行使上述權利，請透過下方聯絡方式與我們聯繫。</p><h2 id="_6-cookie-政策" tabindex="-1">6. Cookie 政策 <a class="header-anchor" href="#_6-cookie-政策" aria-label="Permalink to &quot;6. Cookie 政策&quot;">​</a></h2><p>我們使用以下類型的 Cookie：</p><ul><li><strong>必要 Cookie</strong>：保持登入狀態、記住語言偏好</li><li><strong>分析 Cookie</strong>：統計造訪量和使用模式（使用隱私友善的 Plausible）</li><li><strong>廣告 Cookie</strong>： <ul><li>第三方供應商（包括 Google）使用 Cookie 來根據使用者在您的網站或其他網站上的過往造訪記錄投放廣告。</li><li>Google 使用廣告 Cookie，使其及其合作夥伴能夠根據使用者對您網站和/或網際網路上其他網站的造訪記錄向使用者投放廣告。</li><li>使用者可以造訪 <a href="https://www.google.com/settings/ads" target="_blank" rel="noreferrer">Google 廣告設定</a> 停用個人化廣告。或者，您可以引導使用者造訪 <a href="http://www.aboutads.info/choices/" target="_blank" rel="noreferrer">www.aboutads.info</a> 停用第三方供應商用於個人化廣告的 Cookie。</li></ul></li></ul><p>您可以透過瀏覽器設定管理 Cookie。停用必要 Cookie 可能影響部分功能的正常使用。</p><h2 id="_7-聯絡我們" tabindex="-1">7. 聯絡我們 <a class="header-anchor" href="#_7-聯絡我們" aria-label="Permalink to &quot;7. 聯絡我們&quot;">​</a></h2><p>如您對本隱私條款有任何疑問，或需要行使您的資料權利，請聯繫：</p><ul><li><strong>電子郵件</strong>：<a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>回應時間</strong>：我們會在 15 個工作日內回應您的請求</li></ul>',30)])])}const p=r(i,[["render",e]]);export{u as __pageData,p as default};
